Here's how to test `DataFetcher` with MSTest, covering success, cancellation, and timeouts:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync("http://example.com");

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ErrorStatus_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.NotFound));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("http://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange — handler that delays so cancellation can fire
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler(delay: TimeSpan.FromSeconds(10));
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act — cancel immediately
        cts.Cancel();

        // Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("http://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // framework enforces 3s max
    public async Task FetchAsync_WithTimeout_CompletesWithinLimit()
    {
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("fast")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Pass TestContext.CancellationToken — fires when [Timeout] expires
        var result = await fetcher.FetchAsync(
            "http://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    // Minimal test double — no mocking library needed
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage? _response;
        private readonly TimeSpan _delay;

        public FakeHandler(HttpResponseMessage response) => _response = response;
        public FakeHandler(TimeSpan delay) => _delay = delay;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
            {
                await Task.Delay(_delay, cancellationToken); // throws if cancelled
            }

            return _response ?? new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Why |
|---------|-----|
| `TestContext` via constructor | Enables `CancellationToken` access for timeout cooperation |
| `[Timeout(ms)]` + `_testContext.CancellationToken` | Framework cancels your token when time expires — no hung tests |
| `Assert.ThrowsExactlyAsync<T>` | Validates the exact exception type (not `[ExpectedException]`) |
| `FakeHandler` (custom `HttpMessageHandler`) | Avoids mocking HttpClient directly — which is not designed to be mocked |
| Sealed test class | Performance best practice in MSTest 3.x+ |

The critical insight: always pass `TestContext.CancellationToken` into async calls inside `[Timeout]`-decorated tests — otherwise the timeout kills the test thread but the underlying operation keeps running.
